    await driver.findElement(By.id("password")).sendKeys("Admin2026!")
    await driver.findElement(By.css(".btn")).click()
    await driver.findElement(By.linkText("Productos")).click()
    await driver.findElement(By.css(".block-head")).click()
    await driver.findElement(By.css(".btn--primary")).click()
    await driver.findElement(By.css(".btn--primary")).click()
    await driver.findElement(By.id("pr-cat")).click()
    {
      const dropdown = await driver.findElement(By.id("pr-cat"))
      await dropdown.findElement(By.xpath("//option[. = 'Manual Enciclopedia Collection']")).click()
    }
    await driver.findElement(By.id("pr-name")).click()
    await driver.findElement(By.id("pr-name")).sendKeys("Manual de Test")
